package com.app.stable; import android.os.Bundle; import android.webkit.*; import android.app.Activity; public class MainActivity extends Activity { protected void onCreate(Bundle s) { super.onCreate(s); WebView w = new WebView(this); w.getSettings().setJavaScriptEnabled(true); w.getSettings().setDomStorageEnabled(true); w.setWebChromeClient(new WebChromeClient() { public void onPermissionRequest(PermissionRequest r) { r.grant(r.getResources()); } }); w.loadUrl("file:///android_asset/index.html"); setContentView(w); } }